let accessToken = null;

function checkURLForAccessToken() {
    const urlParams = new URLSearchParams(window.location.hash.slice(1));
    const accessTokenParam = urlParams.get('access_token');

    if (accessTokenParam) {
        accessToken = accessTokenParam;
        window.location.hash = ''; // remove the access token from the URL for security
    }
}

function authorize(redirectURI) {
    const clientID = 'your_client_id';
    const authorizationEndpoint = 'https://your_authorization_server/authorize';
    const responseType = 'token';
    const scope = 'your_scope';
    const state = 'some_random_string'; // use a unique string to protect against CSRF attacks

    const authUrl = `${authorizationEndpoint}?client_id=${clientID}&response_type=${responseType}&redirect_uri=${encodeURIComponent(redirectURI)}&scope=${scope}&state=${state}`;
    window.location.href = authUrl;
}

function callAPI(apiEndpoint, callback) {
    const headers = {
        'Authorization': `Bearer ${accessToken}`
    };

    fetch(`https://your_api_server${apiEndpoint}`, { headers })
        .then(response => response.json())
        .then(data => callback(data))
        .catch(error => console.error('API error:', error));
}